const html = String($input.first().json.data || $input.first().json.body || '');
const text = html
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&[a-z#0-9]+;/gi, ' ')
  .replace(/\s+/g, ' ')
  .trim()
  .slice(0, 8000);

const url = $('Webhook').first().json.body.url;

if (!text || text.length < 50) {
  return [{ json: { error: 'No se pudo leer el contenido del sitio. Puede estar bloqueando bots.' } }];
}

return [{ json: { text, url } }];

