const input = $input.first().json;

// Si el nodo anterior pasó un error (sitio no legible)
if (input.error) {
  return [{ json: { error: input.error } }];
}

// Extraer el texto generado por Gemini
const raw = input.candidates?.[0]?.content?.parts?.[0]?.text || '';

// Buscar el bloque JSON en la respuesta
const match = raw.match(/\{[\s\S]*\}/);
if (!match) {
  return [{ json: { error: 'No se pudo generar el análisis. Intentá de nuevo.' } }];
}

try {
  const result = JSON.parse(match[0]);
  return [{ json: result }];
} catch (e) {
  return [{ json: { error: 'Error al procesar la respuesta de la IA.' } }];
}
